class Solution:
    def solve(self, password: str) -> int:
        n = len(password)
        has_lower = any(c.islower() for c in password)
        has_upper = any(c.isupper() for c in password)
        has_digit = any(c.isdigit() for c in password)
        missing_types = (1 if not has_lower else 0) + (1 if not has_upper else 0) + (1 if not has_digit else 0)

        replacements = 0
        one_counts, two_counts = 0, 0
        i = 2
        while i < n:
            if password[i] == password[i-1] == password[i-2]:
                length = 2
                while i < n and password[i] == password[i-1]:
                    length += 1
                    i += 1
                replacements += length // 3
                if length % 3 == 0: one_counts += 1
                elif length % 3 == 1: two_counts += 1
            else:
                i += 1

        if n < 6:
            return max(missing_types, 6 - n)
        elif n <= 20:
            return max(missing_types, replacements)
        else:
            deletions = n - 20
            replacements -= min(deletions, one_counts * 1) // 1
            replacements -= min(max(deletions - one_counts, 0), two_counts * 2) // 2
            replacements -= max(deletions - one_counts - 2 * two_counts, 0) // 3
            return deletions + max(missing_types, replacements)

